exercises.solution_code:
class Temperature:
    def __init__(self, celsius):
        self.celsius = celsius

    def __repr__(self):
        return f"Temperature({self.celsius!r})"

    def __str__(self):
        return f"{self.celsius}\u00b0C"

tests.content:
from solution import Temperature


def test_init_stores_value():
    t = Temperature(20)
    assert t.celsius == 20


def test_repr_is_unambiguous():
    # repr is for developers: it should look like a call that recreates the object.
    assert repr(Temperature(20)) == "Temperature(20)"


def test_repr_quotes_strings_via_bang_r():
    # Tricky: using {self.celsius!r} keeps repr round-trippable for any value.
    assert repr(Temperature("hot")) == "Temperature('hot')"


def test_str_is_human_readable():
    assert str(Temperature(20)) == "20\u00b0C"


def test_str_and_repr_differ():
    t = Temperature(-5)
    assert str(t) == "-5\u00b0C"
    assert repr(t) == "Temperature(-5)"


def test_containers_use_repr_not_str():
    # Edge: a list prints each element with repr(), never str().
    assert repr([Temperature(1)]) == "[Temperature(1)]"

