exercises.solution_code:
class Version:
    def __init__(self, major, minor, patch):
        self.major = major
        self.minor = minor
        self.patch = patch

    def _key(self):
        return (self.major, self.minor, self.patch)

    def __repr__(self):
        return f"Version({self.major}, {self.minor}, {self.patch})"

    def __eq__(self, other):
        if not isinstance(other, Version):
            return NotImplemented
        return self._key() == other._key()

    def __hash__(self):
        return hash(self._key())

tests.content:
from solution import Version


def test_value_equality():
    assert Version(1, 2, 3) == Version(1, 2, 3)
    assert Version(1, 2, 3) is not Version(1, 2, 3)


def test_unequal_when_any_part_differs():
    assert Version(1, 2, 3) != Version(1, 2, 4)
    assert Version(1, 2, 3) != Version(2, 2, 3)


def test_not_equal_to_foreign_type():
    # Tricky: __eq__ returns NotImplemented for foreign types, so equality
    # falls back to identity and a Version never equals a plain tuple.
    assert Version(1, 2, 3) != (1, 2, 3)
    assert (Version(1, 2, 3) == "1.2.3") is False


def test_hashable_and_dedupes_in_set():
    # Equal objects must hash equally, so a set collapses duplicates.
    s = {Version(1, 0, 0), Version(1, 0, 0), Version(2, 0, 0)}
    assert len(s) == 2


def test_usable_as_dict_key():
    seen = {Version(1, 0, 0): "first"}
    seen[Version(1, 0, 0)] = "updated"
    assert seen == {Version(1, 0, 0): "updated"}
    assert len(seen) == 1


def test_equal_objects_have_equal_hash():
    # The hash/eq contract: a == b implies hash(a) == hash(b).
    a = Version(3, 4, 5)
    b = Version(3, 4, 5)
    assert a == b
    assert hash(a) == hash(b)

