exercises.solution_code:
class Playlist:
    def __init__(self, tracks):
        # Store a private copy so external mutation cannot corrupt us.
        self._tracks = list(tracks)

    def __len__(self):
        return len(self._tracks)

    def __getitem__(self, index):
        # Delegating to the list supports both integer indexing and slicing,
        # and raises IndexError for out-of-range access for free.
        return self._tracks[index]

    def __contains__(self, item):
        return item in self._tracks

    def __repr__(self):
        return f"Playlist({self._tracks!r})"

