exercises.solution_code:
class Between:
    """A callable matcher: Between(low, high)(value) is True when low <= value <= high."""

    def __init__(self, low, high):
        self.low = low
        self.high = high

    def __call__(self, value):
        return self.low <= value <= self.high

    def __repr__(self):
        # A readable repr makes a failing assertion explain what was expected.
        return f"Between({self.low!r}, {self.high!r})"
